package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class ConciseSetGenerator {

    private ConciseSetGenerator() {
    }

    public static Set<TestCase> setCover(TestResults results) {
        Set<TestCase> selected = new HashSet<>();
        if (results == null) {
            return selected;
        }

        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        Set<Integer> uncovered = new HashSet<>(results.getWrongSet());
        if (caseToFiles == null || uncovered.isEmpty()) {
            return selected;
        }

        List<Set<Integer>> coverageCopies = new ArrayList<>();
        for (Set<Integer> fileSet : caseToFiles) {
            if (fileSet == null) {
                coverageCopies.add(new HashSet<>());
            } else {
                coverageCopies.add(new HashSet<>(fileSet));
            }
        }

        while (!uncovered.isEmpty()) {
            int bestIndex = -1;
            int bestCount = 0;

            for (int i = 0; i < coverageCopies.size(); i++) {
                Set<Integer> covered = new HashSet<>(coverageCopies.get(i));
                covered.retainAll(uncovered);
                if (covered.size() > bestCount) {
                    bestCount = covered.size();
                    bestIndex = i;
                }
            }

            if (bestIndex == -1 || bestCount == 0) {
                break;
            }

            TestCase bestCase = results.getTestCase(bestIndex);
            if (bestCase != null) {
                selected.add(bestCase);
            }

            uncovered.removeAll(coverageCopies.get(bestIndex));
        }

        return selected;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

import java.util.List;
import java.util.Random;
import java.util.Set;

public abstract class APyNode<ObjType extends APyObj, DomainType> {

    private List<DomainType> exDomain;
    private List<DomainType> ranDomain;
    protected final Random random;

    public APyNode() {
        this.random = new Random();
    }

    public void setExDomain(List<DomainType> exDomain) {
        this.exDomain = exDomain;
    }

    public List<DomainType> getExDomain() {
        return this.exDomain;
    }

    public void setRanDomain(List<DomainType> ranDomain) {
        this.ranDomain = ranDomain;
    }

    public List<DomainType> getRanDomain() {
        return this.ranDomain;
    }

    public abstract APyNode<?, ?> getLeftChild();

    public abstract APyNode<?, ?> getRightChild();

    public abstract Set<ObjType> genExVals();

    public abstract ObjType genRandVal();
}

package main.rice.node;

import main.rice.obj.PyBoolObj;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class PyBoolNode extends APyNode<PyBoolObj, Integer> {

    public PyBoolNode() {
        super();
    }

    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        List<Integer> domain = getExDomain();
        if (domain == null) {
            return result;
        }

        for (Integer val : domain) {
            if (val == null) {
                continue;
            }
            if (val == 0) {
                result.add(new PyBoolObj(false));
            } else if (val == 1) {
                result.add(new PyBoolObj(true));
            }
        }

        return result;
    }

    @Override
    public PyBoolObj genRandVal() {
        List<Integer> domain = getRanDomain();
        if (domain == null || domain.isEmpty()) {
            return null;
        }

        Integer val = domain.get(this.random.nextInt(domain.size()));
        if (val == null) {
            return null;
        }
        if (val == 0) {
            return new PyBoolObj(false);
        }
        if (val == 1) {
            return new PyBoolObj(true);
        }
        return null;
    }
}

package main.rice.node;

import main.rice.obj.PyFloatObj;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class PyFloatNode extends APyNode<PyFloatObj, Double> {

    public PyFloatNode() {
        super();
    }

    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyFloatObj> genExVals() {
        Set<PyFloatObj> result = new HashSet<>();
        List<Double> domain = getExDomain();
        if (domain == null) {
            return result;
        }

        for (Double val : domain) {
            if (val != null) {
                result.add(new PyFloatObj(val));
            }
        }

        return result;
    }

    @Override
    public PyFloatObj genRandVal() {
        List<Double> domain = getRanDomain();
        if (domain == null || domain.isEmpty()) {
            return null;
        }

        Double val = domain.get(this.random.nextInt(domain.size()));
        if (val == null) {
            return null;
        }
        return new PyFloatObj(val);
    }
}

